package com.ghatana.aep.domain.recommendation;

/**
 * Unified recommendation types across all recommendation domains.
 * 
 * Defines all recommendation categories used by the system's recommendation engines.
 * Covers pattern learning recommendations, cache optimization, and general system improvements.
 * Each recommendation type encapsulates specific actionable suggestions for system optimization.
 *
 * <h2>Recommendation Categories</h2>
 *
 * <h3>Pattern Learning Recommendations (5 types)</h3>
 * <p>
 * Generated by ML-based pattern analysis engines to improve pattern effectiveness:
 * <ul>
 *   <li><b>OPTIMIZATION</b>: Refine existing pattern parameters for better matches</li>
 *   <li><b>TUNING</b>: Adjust pattern weights, thresholds, or time windows</li>
 *   <li><b>REPLACEMENT</b>: Replace ineffective pattern with better alternative</li>
 *   <li><b>DEPRECATION</b>: Mark obsolete/unused patterns for removal</li>
 *   <li><b>ENHANCEMENT</b>: Extend pattern with new capabilities or event types</li>
 * </ul>
 * </p>
 *
 * <h3>Cache Optimization Recommendations (8 types)</h3>
 * <p>
 * Generated by cache analysis engines to improve performance and memory efficiency:
 * <ul>
 *   <li><b>ENABLE_CACHING</b>: Start caching for frequently accessed data</li>
 *   <li><b>OPTIMIZE_CACHE_STRATEGY</b>: Switch cache eviction policy (LRU, LFU, etc.)</li>
 *   <li><b>INCREASE_CACHE_SIZE</b>: Allocate more memory to specific cache layer</li>
 *   <li><b>REMOVE_CACHE_KEY</b>: Disable caching for rarely-used data</li>
 *   <li><b>ADJUST_TTL</b>: Change cache time-to-live for staleness optimization</li>
 *   <li><b>MEMORY_OPTIMIZATION</b>: Reduce overall cache memory footprint</li>
 *   <li><b>PROJECT_SPECIFIC_TUNING</b>: Apply project-specific cache improvements</li>
 *   <li><b>SHARED_CACHE_OPTIMIZATION</b>: Optimize shared cache across services</li>
 * </ul>
 * </p>
 *
 * <h2>Architecture Role</h2>
 * <p>
 * Used by Recommendation Engine to categorize and filter recommendations:
 * <ul>
 *   <li><b>Pattern Learning Engine</b>: Generates OPTIMIZATION, TUNING, REPLACEMENT, DEPRECATION, ENHANCEMENT</li>
 *   <li><b>Cache Optimization Engine</b>: Generates all CACHE_* and MEMORY_OPTIMIZATION types</li>
 *   <li><b>UI Presentation</b>: Groups recommendations by type for user consumption</li>
 *   <li><b>Auto-Application</b>: Determines which recommendations can be auto-applied vs. require approval</li>
 * </ul>
 * </p>
 *
 * <h2>Usage Examples</h2>
 * <pre>{@code
 * // Check recommendation category
 * RecommendationType type = RecommendationType.ENABLE_CACHING;
 *
 * if (type.isCacheOptimization()) {
 *   // Route to cache optimization executor
 *   applyCacheRecommendation(recommendation);
 * } else if (type.isPatternLearning()) {
 *   // Route to pattern learning executor
 *   applyPatternRecommendation(recommendation);
 * }
 *
 * // Parse from external recommendation engine
 * RecommendationType parsed = RecommendationType.fromValue("optimize_cache_strategy");
 * String description = parsed.getDescription();
 * // \"Optimize caching strategy\"
 *
 * // Display to user
 * System.out.println(type.getDescription());
 * }</pre>
 *
 * @doc.type enum
 * @doc.layer domain
 * @doc.purpose recommendation action classifier for pattern and cache optimization
 * @doc.pattern command (each type represents a distinct actionable command/strategy)
 * @doc.test-hints verify type categorization, test category predicates, validate parsing from external sources
 *
 * @see com.ghatana.platform.domain.domain.recommendation.RecommendationPriority
 * @see com.ghatana.platform.domain.domain.pattern.PatternId (related to pattern learning recommendations)
 */
public enum RecommendationType {
    
    // Pattern Learning Recommendations (ML-based pattern improvement)
    OPTIMIZATION("optimization", "Pattern optimization recommendation"),
    TUNING("tuning", "Pattern tuning recommendation"),
    REPLACEMENT("replacement", "Pattern replacement recommendation"),
    DEPRECATION("deprecation", "Pattern deprecation recommendation"),
    ENHANCEMENT("enhancement", "Pattern enhancement recommendation"),
    
    // Cache Optimization Recommendations
    ENABLE_CACHING("enable_caching", "Enable caching for improved performance"),
    OPTIMIZE_CACHE_STRATEGY("optimize_cache_strategy", "Optimize caching strategy"),
    INCREASE_CACHE_SIZE("increase_cache_size", "Increase cache size"),
    REMOVE_CACHE_KEY("remove_cache_key", "Remove unused cache key"),
    ADJUST_TTL("adjust_ttl", "Adjust cache TTL"),
    MEMORY_OPTIMIZATION("memory_optimization", "Optimize memory usage"),
    PROJECT_SPECIFIC_TUNING("project_specific_tuning", "Project-specific tuning"),
    SHARED_CACHE_OPTIMIZATION("shared_cache_optimization", "Shared cache optimization");
    
    private final String value;
    private final String description;
    
    RecommendationType(String value, String description) {
        this.value = value;
        this.description = description;
    }
    
    public String getValue() {
        return value;
    }
    
    public String getDescription() {
        return description;
    }
    
    /**
     * Parse a string value to RecommendationType enum.
     * 
     * @param value The string value to parse
     * @return The corresponding RecommendationType, or null if not found
     */
    public static RecommendationType fromValue(String value) {
        for (RecommendationType type : values()) {
            if (type.value.equals(value)) {
                return type;
            }
        }
        return null;
    }
    
    /**
     * Check if this is a pattern learning recommendation.
     * 
     * @return true if this is a pattern learning recommendation
     */
    public boolean isPatternLearning() {
        return this == OPTIMIZATION || this == TUNING || this == REPLACEMENT || 
               this == DEPRECATION || this == ENHANCEMENT;
    }
    
    /**
     * Check if this is a cache optimization recommendation.
     * 
     * @return true if this is a cache optimization recommendation
     */
    public boolean isCacheOptimization() {
        return this == ENABLE_CACHING || this == OPTIMIZE_CACHE_STRATEGY || 
               this == INCREASE_CACHE_SIZE || this == REMOVE_CACHE_KEY || 
               this == ADJUST_TTL || this == MEMORY_OPTIMIZATION || 
               this == PROJECT_SPECIFIC_TUNING || this == SHARED_CACHE_OPTIMIZATION;
    }
}
